//! Emit enum projections from `endpoint_surface.toml`.

use std::fmt::Write as _;

use super::super::model::GeneratedEnum;

pub(super) fn render_tdbe_enums(enums: &[GeneratedEnum]) -> String {
    let mut out = String::new();
    out.push_str(
        "// @generated DO NOT EDIT - regenerated by build.rs from endpoint_surface.toml\n\n",
    );
    for enum_spec in enums {
        writeln!(out, "/// Wire string enum `{}`.", enum_spec.name).unwrap();
        writeln!(out, "#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]").unwrap();
        writeln!(out, "pub enum {} {{", enum_spec.rust_name).unwrap();
        for variant in &enum_spec.variants {
            writeln!(out, "    {},", variant.rust).unwrap();
        }
        out.push_str("}\n\n");

        writeln!(out, "impl {} {{", enum_spec.rust_name).unwrap();
        out.push_str("    #[must_use]\n");
        out.push_str("    pub fn as_str(&self) -> &'static str {\n");
        out.push_str("        match self {\n");
        for variant in &enum_spec.variants {
            writeln!(
                out,
                "            Self::{} => {:?},",
                variant.rust, variant.wire
            )
            .unwrap();
        }
        out.push_str("        }\n");
        out.push_str("    }\n");
        if enum_spec.rust_name == "Right" {
            out.push('\n');
            out.push_str("    #[must_use]\n");
            out.push_str("    pub fn from_char(c: char) -> Option<Self> {\n");
            out.push_str("        match c {\n");
            out.push_str("            'C' | 'c' => Some(Self::Call),\n");
            out.push_str("            'P' | 'p' => Some(Self::Put),\n");
            out.push_str("            _ => None,\n");
            out.push_str("        }\n");
            out.push_str("    }\n\n");
            out.push_str("    #[must_use]\n");
            out.push_str("    pub fn as_char(&self) -> char {\n");
            out.push_str("        match self {\n");
            out.push_str("            Self::Call => 'C',\n");
            out.push_str("            Self::Put => 'P',\n");
            out.push_str("            Self::Both => '*',\n");
            out.push_str("        }\n");
            out.push_str("    }\n");
        }
        out.push_str("}\n\n");

        writeln!(out, "impl std::fmt::Display for {} {{", enum_spec.rust_name).unwrap();
        out.push_str("    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {\n");
        out.push_str("        f.write_str(self.as_str())\n");
        out.push_str("    }\n");
        out.push_str("}\n\n");

        writeln!(out, "impl TryFrom<&str> for {} {{", enum_spec.rust_name).unwrap();
        out.push_str("    type Error = ();\n\n");
        out.push_str("    fn try_from(value: &str) -> Result<Self, Self::Error> {\n");
        out.push_str("        match value {\n");
        for variant in &enum_spec.variants {
            writeln!(
                out,
                "            {:?} => Ok(Self::{}),",
                variant.wire, variant.rust
            )
            .unwrap();
        }
        if enum_spec.rust_name == "Right" {
            out.push_str("            \"C\" | \"c\" => Ok(Self::Call),\n");
            out.push_str("            \"P\" | \"p\" => Ok(Self::Put),\n");
            out.push_str("            \"*\" => Ok(Self::Both),\n");
        }
        out.push_str("            _ => Err(()),\n");
        out.push_str("        }\n");
        out.push_str("    }\n");
        out.push_str("}\n\n");
    }
    out
}

pub(super) fn render_python_enums(enums: &[GeneratedEnum]) -> String {
    let mut out = String::new();
    out.push_str(
        "// @generated DO NOT EDIT - regenerated by build.rs from endpoint_surface.toml\n\n",
    );
    out.push_str("macro_rules! string_enum {\n");
    out.push_str("    ($name:ident { $($variant:ident => $value:literal),+ $(,)? }) => {\n");
    out.push_str(
        "        #[pyclass(module = \"thetadatadx\", frozen, eq, hash, skip_from_py_object)]\n",
    );
    out.push_str("        #[derive(Clone, Copy, PartialEq, Eq, Hash)]\n");
    out.push_str("        pub(crate) struct $name {\n");
    out.push_str("            value: &'static str,\n");
    out.push_str("        }\n\n");
    out.push_str("        #[pymethods]\n");
    out.push_str("        impl $name {\n");
    out.push_str("            $(\n");
    out.push_str("                #[classattr]\n");
    out.push_str("                const $variant: Self = Self { value: $value };\n");
    out.push_str("            )+\n\n");
    out.push_str("            #[getter]\n");
    out.push_str("            fn value(&self) -> &'static str {\n");
    out.push_str("                self.value\n");
    out.push_str("            }\n\n");
    out.push_str("            fn __str__(&self) -> &'static str {\n");
    out.push_str("                self.value\n");
    out.push_str("            }\n\n");
    out.push_str("            fn __repr__(&self) -> String {\n");
    out.push_str("                format!(\"{}.{}\", stringify!($name), self.value)\n");
    out.push_str("            }\n");
    out.push_str("        }\n");
    out.push_str("    };\n");
    out.push_str("}\n\n");
    for enum_spec in enums {
        writeln!(out, "string_enum!({} {{", enum_spec.name).unwrap();
        for variant in &enum_spec.variants {
            writeln!(out, "    {} => {:?},", variant.python, variant.wire).unwrap();
        }
        out.push_str("});\n\n");
    }
    out.push_str(
        "pub(crate) fn register_string_enums(m: &Bound<'_, PyModule>) -> PyResult<()> {\n",
    );
    for enum_spec in enums {
        writeln!(out, "    m.add_class::<{}>()?;", enum_spec.name).unwrap();
    }
    out.push_str("    Ok(())\n");
    out.push_str("}\n");
    out
}

pub(super) fn render_typescript_enums(enums: &[GeneratedEnum]) -> String {
    let mut out = String::new();
    out.push_str(
        "// @generated DO NOT EDIT - regenerated by build.rs from endpoint_surface.toml\n\n",
    );
    for enum_spec in enums {
        writeln!(out, "#[napi(string_enum)]").unwrap();
        writeln!(out, "pub enum {} {{", enum_spec.name).unwrap();
        for variant in &enum_spec.variants {
            writeln!(out, "    #[napi(value = {:?})]", variant.wire).unwrap();
            writeln!(out, "    {},", variant.rust).unwrap();
        }
        out.push_str("}\n\n");
    }
    out
}
